import { task, batch } from "@trigger.dev/sdk";

export const subTask = task({
  id: "process-item-v1",
  run: async (payload: { id: string }) => {
    return payload.id;
  },
});

export const parentTask = task({
  id: "batch-processor-v1",
  run: async (payload: { ids: string[] }) => {
    const result = await batch.triggerByTaskAndWait(
      subTask,
      payload.ids.map((id) => ({
        payload: { id },
      }))
    );
    return result.items.map((item) => (item.ok ? item.output : item.error));
  },
});
EOF

